class Solution:
    def recoverTree(self, root):
        # Brute force: read in-order into a list, sort the values, write them
        # back during a second in-order pass.
        nodes = []
        def inorder(n):
            if n is None:
                return
            inorder(n.left)
            nodes.append(n)
            inorder(n.right)
        inorder(root)
        vals = sorted(n.val for n in nodes)
        for n, v in zip(nodes, vals):
            n.val = v

