class Solution:
    def recoverTree(self, root):
        first = second = prev = None
        node = root
        # Morris-free explicit in-order using a stack
        stack = []
        while stack or node:
            while node:
                stack.append(node)
                node = node.left
            node = stack.pop()
            if prev and prev.val > node.val:
                if first is None:
                    first = prev
                second = node
            prev = node
            node = node.right
        if first and second:
            first.val, second.val = second.val, first.val

